	outline-color: invert;
	outline-offset: 0pt;
	font-family: -fm-font-family(Hiragino Kaku Gothic ProN,HiraKakuProN-W3);
	font-weight: normal;
	font-stretch: normal;
	font-style: normal;
	font-variant: normal;
	font-size: 16pt;
	color: rgba(15.6863%,15.6863%,15.6863%,1);
	direction: ltr;
	line-height: 1line;
	block-progression: tb;
	text-align: left;
	text-transform: none;
	text-indent: 0pt;
	box-shadow: none;
	box-sizing: content-box;
	vertical-align: baseline;
	-fm-digit-set: roman;
	-fm-space-before: 0line;
